//! # Saturation-Aware Inference Kernels
//!
//! Integration layer for sparse FFN computation using precomputed saturation
//! bitmasks. Provides high-level wrappers around standard inference functions
//! that optionally skip frozen neurons.
//!
//! This module bridges the saturation profiling phase (which generates bitmasks)
//! and the inference phase (which consumes them for sparse ops).

use crate::rknot::saturation_metadata::SaturationMaps;

/// Runtime handle to a loaded saturation map.
///
/// Wraps access to SaturationMaps so inference kernels can:
/// 1. Query frozen status with O(1) bit lookup
/// 2. Estimate layer speedup
/// 3. Safely handle missing saturation data (fallback to dense ops)
#[derive(Debug, Clone)]
pub struct SaturationHandle {
    /// The loaded maps (None if no saturation data available)
    pub maps: Option<SaturationMaps>,
}

impl SaturationHandle {
    /// Creates a handle with no saturation data (dense inference).
    pub fn none() -> Self {
        Self { maps: None }
    }

    /// Creates a handle with saturation maps.
    pub fn with_maps(maps: SaturationMaps) -> Self {
        Self { maps: Some(maps) }
    }

    /// Checks if saturation data is available.
    pub fn is_available(&self) -> bool {
        self.maps.is_some()
    }

    /// Queries frozen status for a neuron (returns false if no saturation data).
    pub fn is_ffn_neuron_frozen(&self, layer_id: u32, neuron_id: u32) -> bool {
        self.maps
            .as_ref()
            .map(|m| m.is_ffn_neuron_frozen(layer_id, neuron_id))
            .unwrap_or(false)
    }

    /// Gets estimated FFN speedup for a layer (returns 1.0 if no saturation data).
    pub fn ffn_speedup_estimate(&self, layer_id: u32) -> f32 {
        self.maps
            .as_ref()
            .map(|m| m.ffn_speedup_estimate(layer_id))
            .unwrap_or(1.0)
    }

    /// Gets percentage of frozen FFN neurons for a layer.
    pub fn pct_frozen(&self, layer_id: u32) -> f32 {
        self.maps
            .as_ref()
            .map(|m| m.pct_frozen(layer_id))
            .unwrap_or(0.0)
    }

    /// Gets mean speedup across all layers.
    pub fn mean_speedup(&self) -> f32 {
        self.maps.as_ref().map(|m| m.mean_speedup()).unwrap_or(1.0)
    }
}

/// Context for sparse FFN computation.
///
/// Holds the precomputed bitmask for one layer, plus dimension info
/// for bounds checking. Passed to kernel functions that implement
/// sparse matrix-vector ops.
#[derive(Debug, Clone)]
pub struct SparseFfnContext {
    /// Layer index
    pub layer_id: u32,
    /// FFN intermediate dimension (typically 8192 for Phi-3)
    pub intermediate_size: u32,
    /// Frozen neuron bitmask (if available)
    pub frozen_neurons: Option<Vec<u8>>,
    /// Count of frozen neurons (cached for stats)
    pub num_frozen: u32,
}

impl SparseFfnContext {
    /// Creates a context for a layer with no saturation data (dense ops).
    pub fn dense(layer_id: u32, intermediate_size: u32) -> Self {
        Self {
            layer_id,
            intermediate_size,
            frozen_neurons: None,
            num_frozen: 0,
        }
    }

    /// Creates a context with saturation data.
    pub fn from_saturation(
        layer_id: u32,
        intermediate_size: u32,
        frozen_neurons: Vec<u8>,
        num_frozen: u32,
    ) -> Self {
        Self {
            layer_id,
            intermediate_size,
            frozen_neurons: Some(frozen_neurons),
            num_frozen,
        }
    }

    /// Loads context from a SaturationHandle and layer info.
    pub fn from_handle(handle: &SaturationHandle, layer_id: u32, intermediate_size: u32) -> Self {
        if let Some(maps) = &handle.maps {
            if let Some(mask) = maps.ffn_frozen_per_layer.get(&layer_id) {
                return Self::from_saturation(
                    layer_id,
                    intermediate_size,
                    mask.frozen_mask.clone(),
                    mask.num_frozen(),
                );
            }
        }
        Self::dense(layer_id, intermediate_size)
    }

    /// Checks if neuron is frozen (returns false if no saturation data).
    pub fn is_frozen(&self, neuron_id: u32) -> bool {
        match &self.frozen_neurons {
            Some(mask) => {
                let byte_idx = (neuron_id / 8) as usize;
                let bit_idx = (neuron_id % 8) as u8;
                byte_idx < mask.len() && (mask[byte_idx] & (1 << bit_idx)) != 0
            }
            None => false,
        }
    }

    /// Percentage of frozen neurons.
    pub fn pct_frozen(&self) -> f32 {
        if self.intermediate_size == 0 {
            0.0
        } else {
            (self.num_frozen as f32 / self.intermediate_size as f32) * 100.0
        }
    }

    /// Estimated speedup from skipping frozen neurons.
    pub fn estimated_speedup(&self) -> f32 {
        if self.frozen_neurons.is_some() && self.num_frozen > 0 {
            let pct = self.pct_frozen() / 100.0;
            if pct >= 0.95 {
                20.0 // cap at 20x
            } else {
                1.0 / (1.0 - pct)
            }
        } else {
            1.0
        }
    }

    /// Returns true if this context can apply sparse ops.
    pub fn can_apply_sparse(&self) -> bool {
        self.frozen_neurons.is_some() && self.num_frozen > 0
    }
}

/// Statistics on sparse FFN execution.
#[derive(Debug, Clone)]
pub struct SparseFfnStats {
    pub layer_id: u32,
    pub dense_flops: u64,  // standard dense FFN: d × m
    pub sparse_flops: u64, // sparse FFN: k × m (k < d)
    pub theoretical_speedup: f32,
    pub actual_wall_us: u64, // wall-clock time in microseconds
}

impl SparseFfnStats {
    /// Creates a stats record.
    pub fn new(layer_id: u32, dense_flops: u64, sparse_flops: u64, actual_wall_us: u64) -> Self {
        let theoretical_speedup = if sparse_flops > 0 {
            dense_flops as f32 / sparse_flops as f32
        } else {
            1.0
        };
        Self {
            layer_id,
            dense_flops,
            sparse_flops,
            theoretical_speedup,
            actual_wall_us,
        }
    }

    /// Estimated actual speedup (wall-clock).
    pub fn actual_speedup(&self, dense_wall_us: u64) -> f32 {
        if self.actual_wall_us > 0 {
            dense_wall_us as f32 / self.actual_wall_us as f32
        } else {
            1.0
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::rknot::saturation_metadata::{LayerFrozenBitmask, SaturationMaps};

    #[test]
    fn saturation_handle_none() {
        let handle = SaturationHandle::none();
        assert!(!handle.is_available());
        assert!(!handle.is_ffn_neuron_frozen(0, 42));
        assert_eq!(handle.ffn_speedup_estimate(0), 1.0);
        assert_eq!(handle.mean_speedup(), 1.0);
    }

    #[test]
    fn saturation_handle_with_maps() {
        let mut mask = LayerFrozenBitmask::new(0, 8192);
        mask.freeze_neuron(100);
        mask.freeze_neuron(200);

        let maps = SaturationMaps::new(32, "variance+gradient".to_string()).insert_layer_mask(mask);

        let handle = SaturationHandle::with_maps(maps);
        assert!(handle.is_available());
        assert!(handle.is_ffn_neuron_frozen(0, 100));
        assert!(!handle.is_ffn_neuron_frozen(0, 101));
    }

    #[test]
    fn sparse_ffn_context_dense() {
        let ctx = SparseFfnContext::dense(0, 8192);
        assert!(!ctx.can_apply_sparse());
        assert_eq!(ctx.pct_frozen(), 0.0);
        assert_eq!(ctx.estimated_speedup(), 1.0);
    }

    #[test]
    fn sparse_ffn_context_from_saturation() {
        let mut frozen = vec![0u8; 1024]; // 8192 neurons
        frozen[0] = 0xFF; // First 8 neurons frozen
        let ctx = SparseFfnContext::from_saturation(0, 8192, frozen, 8);

        assert!(ctx.can_apply_sparse());
        assert!(ctx.is_frozen(0));
        assert!(ctx.is_frozen(7));
        assert!(!ctx.is_frozen(8));
        assert!((ctx.pct_frozen() - (8.0 / 8192.0 * 100.0)).abs() < 0.01);
    }

    #[test]
    fn sparse_ffn_context_from_handle() {
        let mut mask = LayerFrozenBitmask::new(0, 8192);
        for i in 0..800 {
            mask.freeze_neuron(i);
        }
        let maps = SaturationMaps::new(32, "variance+gradient".to_string()).insert_layer_mask(mask);
        let handle = SaturationHandle::with_maps(maps);

        let ctx = SparseFfnContext::from_handle(&handle, 0, 8192);
        assert!(ctx.can_apply_sparse());
        assert_eq!(ctx.num_frozen, 800);
        assert!(ctx.is_frozen(100));
        assert!(!ctx.is_frozen(900));
    }

    #[test]
    fn sparse_ffn_stats_basic() {
        let stats = SparseFfnStats::new(0, 100_000_000, 10_000_000, 1000);
        assert_eq!(stats.layer_id, 0);
        assert!((stats.theoretical_speedup - 10.0).abs() < 0.01);
    }
}
